  ea_step2_title: { zh: '第二步：我该找谁帮忙？（{country} 官方和救助热线）', es: 'Paso 2: ¿a quién acudir? (líneas oficiales de {country})', hi: 'चरण 2: किससे मदद लें? ({country} की आधिकारिक लाइनें)', vi: 'Bước 2: tìm ai giúp? (đường dây chính thức của {country})', ar: 'الخطوة 2: بمن أستعين؟ (خطوط {country} الرسمية)' },
