  ea_check_hint: { zh: '请一步步勾选完成：', es: 'Marca cada paso al completarlo:', hi: 'हर कदम पूरा करके टिक करें:', vi: 'Đánh dấu từng bước khi hoàn thành:', ar: 'حدّد كل خطوة عند إتمامها:' },
  ea_lawshield_title: { zh: '抗辩底层法条盾牌 (Local Tenancy Legal Backup)', es: 'Escudo legal de defensa (Local Tenancy Legal Backup)', hi: 'बचाव का कानूनी कवच (Local Tenancy Legal Backup)', vi: 'Lá chắn pháp lý phòng vệ (Local Tenancy Legal Backup)', ar: 'الدرع القانوني للدفاع (Local Tenancy Legal Backup)' },
  ea_share_tip: { zh: '💡 温馨提醒：任何情况下保护人身安全第一。如中介在对线中言行出格，请果断保留全部信件交由系统信件官投诉！', es: '💡 Recuerda: tu seguridad física es lo primero. Si el agente se pasa de la raya, guarda toda la correspondencia y denúnciala con Letter Officer.', hi: '💡 याद रखें: पहले आपकी सुरक्षा। यदि एजेंट सीमा लाँघे, सभी पत्र सुरक्षित रखें और Letter Officer से शिकायत करें।', vi: '💡 Nhắc nhở: an toàn của bạn là trên hết. Nếu môi giới quá đáng, hãy lưu mọi thư từ và khiếu nại qua Letter Officer.', ar: '💡 تذكير: سلامتك أولًا. إذا تجاوز الوكيل الحدود، احتفظ بكل المراسلات وقدّم شكوى عبر Letter Officer.' },
  ea_legal_basis: { zh: '维权依据：{location} 当地住宅租赁法', es: 'Base legal: ley de alquiler local de {location}', hi: 'कानूनी आधार: {location} का स्थानीय किराया कानून', vi: 'Căn cứ pháp lý: luật thuê nhà địa phương của {location}', ar: 'الأساس القانوني: قانون الإيجار المحلي في {location}' },
  ea_voice_badge: { zh: 'Gemini 语音急救', es: 'Primeros auxilios por voz Gemini', hi: 'Gemini वॉइस फ़र्स्ट-एड', vi: 'Sơ cứu bằng giọng nói Gemini', ar: 'إسعاف صوتي من Gemini' },
  ea_voice_title: { zh: 'AI 智能语音急救向导', es: 'Guía de emergencia por voz con IA', hi: 'AI वॉइस आपातकालीन गाइड', vi: 'Trợ lý khẩn cấp bằng giọng nói AI', ar: 'مرشد الطوارئ الصوتي بالذكاء الاصطناعي' },
  ea_voice_desc: { zh: '遇到突发状况、英语卡壳不知道怎么说？直接对着手机说出你的处境，AI 立刻为你生成 {emergency} 报警口语小抄 + 现场保命指南。', es: '¿Emergencia y no sabes cómo decirlo en inglés? Di tu situación al teléfono y la IA genera al instante un guion para llamar al {emergency} + guía para sobrevivir.', hi: 'आपात स्थिति और अंग्रेज़ी में अटक गए? फ़ोन में अपनी स्थिति बोलें, AI तुरंत {emergency} कॉल स्क्रिप्ट + जीवनरक्षक गाइड बना देगा।', vi: 'Gặp tình huống khẩn và bí tiếng Anh? Nói hoàn cảnh của bạn vào điện thoại, AI lập tức tạo kịch bản gọi {emergency} + hướng dẫn sinh tồn.', ar: 'حالة طارئة ولا تعرف قولها بالإنجليزية؟ قل وضعك للهاتف، وينشئ الذكاء الاصطناعي فورًا نص اتصال {emergency} + دليل النجاة.' },
  ea_listening: { zh: '正在聆听，请说明你的状况…（再次点击麦克风可停止）', es: 'Escuchando, describe tu situación… (toca el micrófono otra vez para parar)', hi: 'सुन रहे हैं, अपनी स्थिति बताएँ… (रोकने के लिए माइक फिर दबाएँ)', vi: 'Đang nghe, hãy nói tình huống của bạn… (chạm micro lần nữa để dừng)', ar: 'نستمع، صف وضعك… (اضغط الميكروفون مجددًا للإيقاف)' },
  ea_analyzing: { zh: 'AI 正在紧急分析最优对策...', es: 'La IA analiza la mejor estrategia...', hi: 'AI सर्वोत्तम रणनीति का विश्लेषण कर रहा है...', vi: 'AI đang phân tích phương án tối ưu...', ar: 'الذكاء الاصطناعي يحلّل أفضل استراتيجية...' },
  ea_voice_unavailable: { zh: '🎤 当前环境（如预览沙盒或未授权麦克风）无法调用实时语音识别。你可以在下方直接输入你的处境，或点此体验一个示例场景：', es: '🎤 Este entorno (sandbox o micrófono sin permiso) no permite voz en vivo. Escribe tu situación abajo o prueba un ejemplo:', hi: '🎤 यह वातावरण (सैंडबॉक्स या बिना अनुमति माइक) लाइव वॉइस नहीं चला सकता। नीचे अपनी स्थिति लिखें या उदाहरण आज़माएँ:', vi: '🎤 Môi trường này (sandbox hoặc micro chưa cấp quyền) không dùng được giọng nói trực tiếp. Hãy nhập tình huống bên dưới hoặc thử một ví dụ:', ar: '🎤 هذه البيئة (وضع معزول أو ميكروفون غير مصرّح) لا تدعم الصوت المباشر. اكتب وضعك بالأسفل أو جرّب مثالًا:' },
  ea_voice_example_btn: { zh: '🎬 体验示例场景：「有人在街上袭击我」', es: '🎬 Probar ejemplo: «Alguien me ataca en la calle»', hi: '🎬 उदाहरण आज़माएँ: «सड़क पर कोई मुझ पर हमला कर रहा है»', vi: '🎬 Thử ví dụ: «Có người tấn công tôi trên phố»', ar: '🎬 جرّب مثالًا: «شخص يهاجمني في الشارع»' },
  ea_voice_example_text: { zh: '刚刚有人在街上袭击了我！', es: '¡Alguien acaba de atacarme en la calle!', hi: 'अभी सड़क पर किसी ने मुझ पर हमला किया!', vi: 'Có người vừa tấn công tôi trên phố!', ar: 'هاجمني أحدهم للتو في الشارع!' },
