  ea_mic_listening: { zh: '聆听中 · 点击停止', es: 'Escuchando · toca para parar', hi: 'सुन रहे हैं · रोकने के लिए दबाएँ', vi: 'Đang nghe · chạm để dừng', ar: 'يستمع · اضغط للإيقاف' },
  ea_strategy_badge: { zh: '🚨 最高优先保命策略', es: '🚨 Estrategia vital prioritaria', hi: '🚨 सर्वोच्च जीवनरक्षक रणनीति', vi: '🚨 Chiến lược sinh tồn ưu tiên', ar: '🚨 استراتيجية النجاة الأولى' },
  ea_strategy_title: { zh: '直接呼叫母语口译官！', es: '¡Pide un intérprete en tu idioma!', hi: 'अपनी भाषा का दुभाषिया माँगें!', vi: 'Yêu cầu thông dịch viên tiếng mẹ đẻ!', ar: 'اطلب مترجمًا بلغتك مباشرة!' },
  ea_strategy_desc: { zh: '无论您的英语在这时卡壳得多厉害，无需任何语法，只需在 {emergency} 电话接通的第一秒，用嘴巴对着话筒高喊：', es: 'No importa cuánto se te trabe el inglés; en cuanto conecte el {emergency}, grita al teléfono:', hi: 'अंग्रेज़ी कितनी भी अटके, {emergency} जुड़ते ही फ़ोन में ज़ोर से बोलें:', vi: 'Dù tiếng Anh có bí đến đâu, ngay khi {emergency} kết nối, hãy hô vào điện thoại:', ar: 'مهما تعثّرت إنجليزيتك، بمجرد اتصال {emergency} اصرخ في الهاتف:' },
  ea_strategy_desc2: { zh: '【完全免费 & 10秒级接驳】{country} {emergency} 应急调配中心不仅会立即定位您，还会在10秒内接入国家级免费电话口译服务。专业口译官将全程在三方通话中帮您翻译所有案情！', es: '[Gratis y en ~10 s] El centro {emergency} de {country} te ubica y conecta un intérprete telefónico nacional gratuito en segundos, que traduce todo en una llamada a tres.', hi: '[मुफ़्त, ~10 सेकंड] {country} का {emergency} केंद्र आपको लोकेट करता है और सेकंडों में राष्ट्रीय मुफ़्त फ़ोन-दुभाषिया जोड़ता है, जो तीन-तरफ़ा कॉल में सब अनुवाद करता है।', vi: '[Miễn phí, ~10 giây] Trung tâm {emergency} của {country} định vị bạn và kết nối thông dịch viên điện thoại quốc gia miễn phí trong vài giây, dịch mọi việc trong cuộc gọi ba bên.', ar: '[مجاني، ~10 ثوانٍ] مركز {emergency} في {country} يحدد موقعك ويصلك بمترجم هاتفي وطني مجاني خلال ثوانٍ يترجم كل شيء في مكالمة ثلاثية.' },
  ea_loc_label: { zh: '您的实时精准定位', es: 'Tu ubicación exacta en tiempo real', hi: 'आपकी सटीक रीयल-टाइम लोकेशन', vi: 'Vị trí chính xác thời gian thực của bạn', ar: 'موقعك الدقيق الآني' },
  ea_loc_gps: { zh: '已启用 GPS · {country} 定位', es: 'GPS activo · ubicación en {country}', hi: 'GPS चालू · {country} में लोकेशन', vi: 'GPS bật · định vị tại {country}', ar: 'GPS مفعّل · تحديد الموقع في {country}' },
  ea_loc_readout: { zh: '📢 电话接通后，请大声、清晰地将上方英文地址读给 {emergency} 接线员', es: '📢 Al conectar, lee en voz alta y clara la dirección de arriba al operador del {emergency}', hi: '📢 कॉल जुड़ते ही ऊपर का पता {emergency} ऑपरेटर को ज़ोर से, साफ़ पढ़ें', vi: '📢 Khi kết nối, đọc to và rõ địa chỉ phía trên cho tổng đài {emergency}', ar: '📢 عند الاتصال، اقرأ العنوان أعلاه بصوت عالٍ وواضح لعامل {emergency}' },
  ea_hotline_label: { zh: '{country} 官方紧急救援热线', es: 'Línea oficial de emergencia de {country}', hi: '{country} की आधिकारिक आपातकालीन लाइन', vi: 'Đường dây khẩn cấp chính thức của {country}', ar: 'خط الطوارئ الرسمي في {country}' },
  ea_quickdial: { zh: '一键快速紧急拨号', es: 'Marcado rápido de emergencia', hi: 'त्वरित आपातकालीन डायल', vi: 'Gọi khẩn nhanh', ar: 'اتصال طوارئ سريع' },
  ea_hotline_desc: { zh: '{country} 紧急救援电话（警察、救护、消防统一由 {emergency} 接通并人工分流。若您英文受限，请在接通后立即大声告知 “{interpreter}, Please！”）。', es: 'Emergencias de {country} (policía, ambulancia y bomberos via {emergency}). Si tu inglés es limitado, al conectar di alto: "{interpreter}, Please!".', hi: '{country} आपातकाल (पुलिस, एम्बुलेंस, दमकल सब {emergency} से)। अंग्रेज़ी सीमित हो तो जुड़ते ही ज़ोर से कहें: "{interpreter}, Please!"।', vi: 'Khẩn cấp {country} (cảnh sát, cứu thương, cứu hỏa đều qua {emergency}). Nếu tiếng Anh hạn chế, khi kết nối hãy nói to: "{interpreter}, Please!".', ar: 'طوارئ {country} (شرطة وإسعاف وإطفاء عبر {emergency}). إن كانت إنجليزيتك محدودة، قل بصوت عالٍ عند الاتصال: "{interpreter}, Please!".' },
  ea_dial_click: { zh: '点击拨打', es: 'Toca para llamar', hi: 'कॉल करने के लिए दबाएँ', vi: 'Chạm để gọi', ar: 'اضغط للاتصال' },
  ea_cheat_title: { zh: '急救口译英文小抄（直接照读）', es: 'Guion en inglés para emergencias (lee tal cual)', hi: 'आपातकालीन अंग्रेज़ी स्क्रिप्ट (सीधे पढ़ें)', vi: 'Kịch bản tiếng Anh khẩn cấp (đọc nguyên văn)', ar: 'نص إنجليزي للطوارئ (اقرأه كما هو)' },
  ea_cheat_copy_hint: { zh: '点击一键复制', es: 'Toca para copiar', hi: 'कॉपी के लिए दबाएँ', vi: 'Chạm để sao chép', ar: 'اضغط للنسخ' },
  ea_copy_english: { zh: '复制英文', es: 'Copiar inglés', hi: 'अंग्रेज़ी कॉपी', vi: 'Sao chép tiếng Anh', ar: 'نسخ الإنجليزية' },
