  dg_s_t1_note: { zh: '可带零食/常用药/数码配件，不带液体与违禁品。机场或 city 当面交付。', es: 'Llevo snacks/medicinas comunes/accesorios electrónicos; nada líquido ni prohibido. Entrega en mano en el aeropuerto o el centro.', hi: 'स्नैक्स/सामान्य दवाइयाँ/डिजिटल एक्सेसरीज़ ले जा सकती हूँ; कोई तरल या प्रतिबंधित नहीं। एयरपोर्ट या सिटी में आमने-सामने।', vi: 'Có thể mang đồ ăn vặt/thuốc thông dụng/phụ kiện số; không mang chất lỏng và hàng cấm. Giao tận tay ở sân bay hoặc trung tâm.', ar: 'يمكنني حمل وجبات خفيفة/أدوية شائعة/ملحقات إلكترونية؛ لا سوائل أو ممنوعات. التسليم باليد في المطار أو وسط المدينة.' },
  dg_s_t2_user: { zh: '在悉尼的 Leo', es: 'Leo (en Sídney)', hi: 'लियो (सिडनी में)', vi: 'Leo (ở Sydney)', ar: 'ليو (في سيدني)' },
  dg_s_t2_from: { zh: '北京 首都', es: 'Pekín Capital', hi: 'बीजिंग कैपिटल', vi: 'Bắc Kinh Thủ Đô', ar: 'بكين العاصمة' },
  dg_s_t2_to: { zh: '悉尼 Kingsford-Smith', es: 'Sídney Kingsford-Smith', hi: 'सिडनी Kingsford-Smith', vi: 'Sydney Kingsford-Smith', ar: 'سيدني Kingsford-Smith' },
  dg_s_t2_date: { zh: '7月20日', es: '20 jul', hi: '20 जुलाई', vi: '20 thg 7', ar: '20 يوليو' },
  dg_s_t2_note: { zh: '行李额充足，优先带轻小件。落地后 UNSW 附近面交。', es: 'Tengo espacio de sobra; prefiero cosas pequeñas y ligeras. Entrega cerca de UNSW al aterrizar.', hi: 'सामान की जगह काफ़ी है; हल्की-छोटी चीज़ें प्राथमिकता। उतरने के बाद UNSW के पास मिलना।', vi: 'Dư nhiều ký, ưu tiên đồ nhỏ nhẹ. Giao gần UNSW sau khi hạ cánh.', ar: 'لديّ متسع كبير للأمتعة، أفضّل الأشياء الصغيرة الخفيفة. التسليم قرب UNSW بعد الوصول.' },
  dg_s_r1_user: { zh: '想家的 Mia', es: 'Mia (con morriña)', hi: 'मिया (घर की याद में)', vi: 'Mia (nhớ nhà)', ar: 'ميا (تحنّ للوطن)' },
  dg_s_r1_item: { zh: '老干妈×4 + 柳州螺蛳粉×6', es: 'Lao Gan Ma ×4 + fideos Luosifen ×6', hi: 'लाओ गन मा ×4 + लुओसिफेन नूडल्स ×6', vi: 'Lao Gan Ma ×4 + bún ốc Liễu Châu ×6', ar: 'لاو قان ما ×4 + نودلز لوسيفن ×6' },
  dg_s_r1_note: { zh: '到墨尔本就行，Clayton/City 都方便面交。', es: 'Con que llegue a Melbourne basta; Clayton o el centro me van bien para la entrega.', hi: 'मेलबर्न पहुँच जाए तो काफ़ी; Clayton/City में मिलना सुविधाजनक।', vi: 'Tới Melbourne là được; Clayton/trung tâm đều tiện giao.', ar: 'يكفي أن تصل إلى ملبورن؛ كلايتون أو وسط المدينة مناسبان للتسليم.' },
  dg_s_r2_user: { zh: '新生小陈', es: 'Chen (recién llegado)', hi: 'चेन (नया छात्र)', vi: 'Tiểu Trần (tân sinh viên)', ar: 'تشين (طالب جديد)' },
  dg_s_r2_item: { zh: '连花清瘟 + 感冒灵颗粒（常备药）', es: 'Lianhua Qingwen + gránulos para resfriado (botiquín)', hi: 'लियानहुआ चिंगवेन + सर्दी के दाने (दवाइयाँ)', vi: 'Liên Hoa Thanh Ôn + thuốc cảm dạng hạt (thuốc thường dùng)', ar: 'ليانهوا تشينغ وين + حبيبات للزكام (أدوية شائعة)' },
  dg_s_r2_note: { zh: '悉尼，急用，酬金可再聊。', es: 'En Sídney, lo necesito urgente; la recompensa es negociable.', hi: 'सिडनी, जल्दी चाहिए; इनाम पर बात हो सकती है।', vi: 'Ở Sydney, cần gấp; tiền công có thể thương lượng.', ar: 'في سيدني، عاجل؛ المكافأة قابلة للنقاش.' },
