  eh_role_find_guide: { zh: '我要找本地向导', es: 'Buscar guía local', hi: 'लोकल गाइड खोजें', vi: 'Tìm hướng dẫn địa phương', ar: 'ابحث عن مرشد محلي' },
  eh_role_be_guide: { zh: '我是本届向导 (创建Profile)', es: 'Soy guía (crear perfil)', hi: 'मैं गाइड हूँ (प्रोफ़ाइल बनाएँ)', vi: 'Tôi là hướng dẫn (tạo hồ sơ)', ar: 'أنا مرشد (إنشاء ملف)' },
